  "settings.accentColorDescription": { "zh-CN": "按钮、链接等的强调色", en: "Accent color for buttons, links, and more", ja: "ボタンやリンクなどのアクセントカラー", fr: "Couleur d’accent pour les boutons, liens, etc.", de: "Akzentfarbe für Schaltflächen, Links und mehr", es: "Color de acento para botones, enlaces y más" },
