  "settings.boldColor": { "zh-CN": "粗体颜色", en: "Bold color", ja: "太字の色", fr: "Couleur du gras", de: "Fettschriftfarbe", es: "Color de negrita" },
  "settings.boldColorDescription": { "zh-CN": "**粗体文本** 的颜色，应用于源码、实时预览与阅读模式", en: "Color of **bold text** across source, live-preview, and reading modes", ja: "**太字テキスト** の色（ソース・ライブプレビュー・閲覧モード共通）", fr: "Couleur du texte **gras** en modes source, aperçu et lecture", de: "Farbe von **fett gedrucktem Text** in Quelltext-, Live-Vorschau- und Lesemodus", es: "Color del **texto en negrita** en modos código, vista previa y lectura" },
  "settings.autoLinkUrls": { "zh-CN": "链接可点击", en: "Clickable links", ja: "URL をリンク化", fr: "Liens cliquables", de: "Klickbare Links", es: "Enlaces clicables" },
  "settings.autoLinkUrlsDescription": { "zh-CN": "开启后，直接输入的域名（如 github.com/zjok/mindzj）在实时预览和阅读模式中会显示为链接样式，点击用默认浏览器打开；关闭后这些域名为普通文本、无样式、不可跳转", en: "When on, bare URLs (e.g. github.com/zjok/mindzj) render as clickable links in live-preview and reading modes and open in your default browser. When off, the same text is rendered as plain, unstyled, non-interactive text.", ja: "オンのとき、ベタ書きのURL（例: github.com/zjok/mindzj）をライブプレビュー/閲覧モードでリンク表示し、クリックで既定のブラウザで開きます。オフでは同じ文字列は装飾なしの普通のテキストになります。", fr: "Lorsqu'activé, les URL brutes (ex. github.com/zjok/mindzj) s'affichent comme des liens cliquables en aperçu et lecture, et s'ouvrent dans le navigateur par défaut. Désactivé, ce texte apparaît brut, sans style, non interactif.", de: "Wenn aktiviert, werden nackte URLs (z. B. github.com/zjok/mindzj) in Live-Vorschau und Lesemodus als klickbare Links gerendert und im Standardbrowser geöffnet. Wenn deaktiviert, erscheinen sie als einfacher Text ohne Stil und ohne Interaktion.", es: "Cuando está activo, las URL simples (p. ej. github.com/zjok/mindzj) se muestran como enlaces clicables en vista previa y lectura, y se abren en el navegador predeterminado. Si se desactiva, se muestran como texto plano sin estilo ni interacción." },
  "settings.selectionColor": { "zh-CN": "文本选中颜色", en: "Selection color", ja: "選択範囲の色", fr: "Couleur de sélection", de: "Auswahlfarbe", es: "Color de selección" },
  "settings.selectionColorDescription": { "zh-CN": "鼠标选中文字时的背景颜色", en: "Background color of text selection", ja: "テキスト選択時の背景色", fr: "Couleur de fond du texte sélectionné", de: "Hintergrundfarbe der Textauswahl", es: "Color de fondo del texto seleccionado" },
