export function normalizeLocale(locale?: string | null): SupportedLocale {
  const value = (locale || "").trim().toLowerCase();
  if (value === "zh-cn" || value === "zh" || value === "zh-hans") return "zh-CN";
  if (value === "en" || value.startsWith("en-")) return "en";
  if (value === "ja" || value.startsWith("ja-")) return "ja";
  if (value === "fr" || value.startsWith("fr-")) return "fr";
  if (value === "de" || value.startsWith("de-")) return "de";
  if (value === "es" || value.startsWith("es-")) return "es";
  return "zh-CN";
}

export function currentLocale(): SupportedLocale {
  return normalizeLocale(settingsStore.settings().locale);
}

export function formatMessage(template: string, vars?: Record<string, string | number>): string {
  if (!vars) return template;
  return template.replace(/\{(\w+)\}/g, (_, key) =>
    Object.prototype.hasOwnProperty.call(vars, key) ? String(vars[key]) : "",
  );
}

export function t(key: string, vars?: Record<string, string | number>, locale = currentLocale()): string {
  const entry = MESSAGES[key];
  if (!entry) return key;
  return formatMessage(entry[locale] ?? entry.en, vars);
}

export function getLanguageOptions() {
  return SUPPORTED_LOCALES.map((value) => ({ value, label: LOCALE_LABELS[value] }));
}

export function getWeekdayLabels(locale = currentLocale()): string[] {
  const formatter = new Intl.DateTimeFormat(locale, { weekday: "short" });
  const monday = new Date(Date.UTC(2024, 0, 1));
  return Array.from({ length: 7 }, (_, index) =>
    formatter.format(new Date(monday.getTime() + index * 24 * 60 * 60 * 1000)),
  );
}

export function formatMonthYear(year: number, month: number, locale = currentLocale()): string {
  return new Intl.DateTimeFormat(locale, { year: "numeric", month: "long" }).format(
    new Date(year, month, 1),
  );
}

/**
 * Localized full month names (12 entries, January..December for the
 * current locale). Used by the calendar's year/month picker popup.
 */
export function getMonthLabels(locale = currentLocale()): string[] {
  const formatter = new Intl.DateTimeFormat(locale, { month: "long" });
  return Array.from({ length: 12 }, (_, idx) => formatter.format(new Date(2000, idx, 1)));
}
